// Some portions generated by Codex

package org.eclipse.rdf4j.query.algebra.evaluation.sketch;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.Statement;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.junit.jupiter.api.Test;

class SketchBasedJoinEstimatorLongIdTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();

	private static SketchBasedJoinEstimator.Config config() {
		return SketchBasedJoinEstimator.Config.defaults()
				.withNominalEntries(128)
				.withSubjectBucketCount(64)
				.withPredicateBucketCount(64)
				.withObjectBucketCount(64)
				.withContextBucketCount(16)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withRefreshSleepMillis(5);
	}

	@Test
	void rebuildAndIncrementalUseTheSameLongIds() {
		IRI leftPredicate = iri("urn:long-id:p:left");
		IRI rightPredicate = iri("urn:long-id:p:right");
		IRI sharedObject = iri("urn:long-id:o:shared");
		Resource sharedSubject = iri("urn:long-id:s:shared");
		List<Statement> statements = List.of(
				st(sharedSubject, leftPredicate, sharedObject),
				st(sharedSubject, rightPredicate, literal("literal stored by id")),
				st(iri("urn:long-id:s:other"), leftPredicate, sharedObject));

		StubSketchStatementSource rebuildSource = new StubSketchStatementSource();
		rebuildSource.addAll(statements);
		SketchBasedJoinEstimator rebuilt = new SketchBasedJoinEstimator(rebuildSource, config());
		rebuilt.rebuild();

		StubSketchStatementSource incrementalSource = new StubSketchStatementSource();
		SketchBasedJoinEstimator incremental = new SketchBasedJoinEstimator(incrementalSource, config());
		for (Statement statement : statements) {
			SketchStatementSource.StatementIds ids = incrementalSource.addAndReturnIds(statement);
			incremental.addStatementIds(ids);
		}
		incremental.debugFlushPendingIncremental();

		long leftPredicateId = rebuildSource.idOf(SketchBasedJoinEstimator.Component.P, leftPredicate).orElseThrow();
		long sharedObjectId = rebuildSource.idOf(SketchBasedJoinEstimator.Component.O, sharedObject).orElseThrow();
		long sharedSubjectId = rebuildSource.idOf(SketchBasedJoinEstimator.Component.S, sharedSubject).orElseThrow();
		long rightPredicateId = rebuildSource.idOf(SketchBasedJoinEstimator.Component.P, rightPredicate).orElseThrow();

		assertEqualEstimate(rebuilt.cardinalitySingle(SketchBasedJoinEstimator.Component.P, leftPredicateId),
				incremental.cardinalitySingle(SketchBasedJoinEstimator.Component.P, leftPredicateId));
		assertEqualEstimate(rebuilt.cardinalityPair(SketchBasedJoinEstimator.Pair.PO, leftPredicateId, sharedObjectId),
				incremental.cardinalityPair(SketchBasedJoinEstimator.Pair.PO, leftPredicateId, sharedObjectId));
		assertEqualEstimate(
				rebuilt.estimateJoinOn(SketchBasedJoinEstimator.Component.S,
						SketchBasedJoinEstimator.Component.P, leftPredicateId,
						SketchBasedJoinEstimator.Component.P, rightPredicateId),
				incremental.estimateJoinOn(SketchBasedJoinEstimator.Component.S,
						SketchBasedJoinEstimator.Component.P, leftPredicateId,
						SketchBasedJoinEstimator.Component.P, rightPredicateId));
		assertEquals(1.0d,
				rebuilt.estimateCount(SketchBasedJoinEstimator.Component.O, sharedSubjectId, leftPredicateId,
						SketchStatementSource.UNBOUND_ID, SketchStatementSource.DEFAULT_CONTEXT_ID),
				0.0d);
	}

	@Test
	void deleteTombstonesAndDefaultContextUseLongIds() {
		IRI predicate = iri("urn:long-id:p:delete");
		IRI namedContext = iri("urn:long-id:c:named");
		Statement defaultGraph = st(iri("urn:long-id:s:default"), predicate, iri("urn:long-id:o:default"));
		Statement namedGraph = st(iri("urn:long-id:s:named"), predicate, iri("urn:long-id:o:named"), namedContext);

		StubSketchStatementSource source = new StubSketchStatementSource();
		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(source, config());

		SketchStatementSource.StatementIds defaultIds = source.addAndReturnIds(defaultGraph);
		SketchStatementSource.StatementIds namedIds = source.addAndReturnIds(namedGraph);
		estimator.addStatementIds(defaultIds);
		estimator.addStatementIds(namedIds);
		estimator.debugFlushPendingIncremental();

		long predicateId = source.idOf(SketchBasedJoinEstimator.Component.P, predicate).orElseThrow();
		long namedContextId = source.idOf(SketchBasedJoinEstimator.Component.C, namedContext).orElseThrow();
		assertEquals(1.0d, estimator.cardinalityPair(SketchBasedJoinEstimator.Pair.PC, predicateId,
				SketchStatementSource.DEFAULT_CONTEXT_ID), 0.0d);
		assertEquals(1.0d, estimator.cardinalityPair(SketchBasedJoinEstimator.Pair.PC, predicateId, namedContextId),
				0.0d);

		source.remove(defaultGraph);
		estimator.deleteStatementIds(defaultIds);
		estimator.debugFlushPendingIncremental();

		assertEquals(0.0d, estimator.cardinalityPair(SketchBasedJoinEstimator.Pair.PC, predicateId,
				SketchStatementSource.DEFAULT_CONTEXT_ID), 0.0d);
		assertTrue(estimator.cardinalityPair(SketchBasedJoinEstimator.Pair.PC, predicateId, namedContextId) > 0.0d);
	}

	private static IRI iri(String value) {
		return VF.createIRI(value);
	}

	private static Literal literal(String value) {
		return VF.createLiteral(value);
	}

	private static Statement st(Resource subject, IRI predicate, org.eclipse.rdf4j.model.Value object) {
		return VF.createStatement(subject, predicate, object);
	}

	private static Statement st(Resource subject, IRI predicate, org.eclipse.rdf4j.model.Value object,
			Resource context) {
		return VF.createStatement(subject, predicate, object, context);
	}

	private static void assertEqualEstimate(double expected, double actual) {
		assertEquals(expected, actual, Math.max(0.000001d, Math.abs(expected) * 0.000001d));
	}
}
